"use client";

import { useState, useCallback } from "react";
import {
  Trash2,
  ChevronLeft,
  ChevronRight,
  Image as ImageIcon,
  Loader2,
  X,
} from "lucide-react";
import type { Media } from "../../types";

interface MediaLibraryProps {
  media: Media[];
  total: number;
  onUpload: (file: File) => Promise<void>;
  onDelete: (id: string) => void;
  onSelect?: (media: Media) => void;
  page: number;
  onPageChange: (page: number) => void;
  pageSize?: number;
}

export function MediaLibrary({
  media,
  total,
  onUpload,
  onDelete,
  onSelect,
  page,
  onPageChange,
  pageSize = 24,
}: MediaLibraryProps) {
  const [isUploading, setIsUploading] = useState(false);
  const [dragOver, setDragOver] = useState(false);
  const [deleteConfirm, setDeleteConfirm] = useState<string | null>(null);
  const [selectedId, setSelectedId] = useState<string | null>(null);

  const totalPages = Math.max(1, Math.ceil(total / pageSize));
  const isSelectMode = !!onSelect;

  const handleFile = useCallback(
    async (file: File) => {
      if (!file.type.startsWith("image/") && !file.type.startsWith("video/")) {
        return;
      }
      setIsUploading(true);
      try {
        await onUpload(file);
      } finally {
        setIsUploading(false);
      }
    },
    [onUpload],
  );

  const handleDrop = useCallback(
    (e: React.DragEvent) => {
      e.preventDefault();
      setDragOver(false);
      const files = Array.from(e.dataTransfer.files);
      if (files.length > 0) {
        handleFile(files[0]);
      }
    },
    [handleFile],
  );

  function handleDelete(id: string) {
    if (deleteConfirm === id) {
      onDelete(id);
      setDeleteConfirm(null);
    } else {
      setDeleteConfirm(id);
    }
  }

  function handleSelect(item: Media) {
    if (isSelectMode) {
      setSelectedId(item.id);
      onSelect?.(item);
    }
  }

  function formatSize(bytes: number | null): string {
    if (!bytes) return "-";
    if (bytes < 1024) return `${bytes} B`;
    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
    return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
  }

  function formatDate(dateStr: string): string {
    return new Date(dateStr).toLocaleDateString("nl-NL", {
      day: "numeric",
      month: "short",
      year: "numeric",
    });
  }

  return (
    <div className="space-y-4">
      {/* Upload dropzone */}
      <div
        onDragOver={(e) => {
          e.preventDefault();
          setDragOver(true);
        }}
        onDragLeave={() => setDragOver(false)}
        onDrop={handleDrop}
        className={`flex flex-col items-center justify-center rounded-lg border-2 border-dashed p-8 transition-colors ${
          dragOver
            ? "border-primary bg-primary/5"
            : "border-border hover:border-primary/50"
        }`}
      >
        {isUploading ? (
          <div className="flex items-center gap-2">
            <Loader2 className="h-6 w-6 animate-spin text-primary" />
            <span className="text-sm text-muted-foreground">
              Bezig met uploaden...
            </span>
          </div>
        ) : (
          <>
            <ImageIcon className="mb-2 h-8 w-8 text-muted-foreground" />
            <p className="text-sm text-muted-foreground">
              Sleep bestanden hierheen of{" "}
              <label className="cursor-pointer text-primary hover:underline">
                kies bestanden
                <input
                  type="file"
                  accept="image/*,video/*"
                  onChange={(e) => {
                    const file = e.target.files?.[0];
                    if (file) handleFile(file);
                    e.target.value = "";
                  }}
                  className="hidden"
                />
              </label>
            </p>
          </>
        )}
      </div>

      {/* Media grid */}
      {media.length === 0 ? (
        <div className="flex flex-col items-center justify-center rounded-lg border border-border px-4 py-12 text-center">
          <ImageIcon className="mb-3 h-8 w-8 text-muted-foreground" />
          <p className="text-sm text-muted-foreground">
            Nog geen media ge&uuml;pload.
          </p>
        </div>
      ) : (
        <div className="grid grid-cols-2 gap-4 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6">
          {media.map((item) => {
            const isImage = item.mime_type?.startsWith("image/");
            const isSelected = selectedId === item.id;

            return (
              <div
                key={item.id}
                className={`group relative overflow-hidden rounded-lg border transition-all ${
                  isSelected
                    ? "border-primary ring-2 ring-primary"
                    : "border-border hover:border-primary/50"
                } ${isSelectMode ? "cursor-pointer" : ""}`}
                onClick={() => handleSelect(item)}
              >
                {/* Thumbnail */}
                <div className="aspect-square bg-muted">
                  {isImage ? (
                    <img
                      src={item.url}
                      alt={item.alt_text ?? item.filename}
                      className="h-full w-full object-cover"
                    />
                  ) : (
                    <div className="flex h-full w-full items-center justify-center">
                      <ImageIcon className="h-8 w-8 text-muted-foreground" />
                    </div>
                  )}
                </div>

                {/* Info overlay */}
                <div className="px-2 py-1.5">
                  <p
                    className="truncate text-xs font-medium text-foreground"
                    title={item.filename}
                  >
                    {item.filename}
                  </p>
                  <p className="text-xs text-muted-foreground">
                    {formatSize(item.size_bytes)} &middot;{" "}
                    {formatDate(item.created_at)}
                  </p>
                </div>

                {/* Delete button */}
                {!isSelectMode && (
                  <button
                    type="button"
                    onClick={(e) => {
                      e.stopPropagation();
                      handleDelete(item.id);
                    }}
                    className={`absolute right-1.5 top-1.5 rounded-full p-1 transition-all ${
                      deleteConfirm === item.id
                        ? "bg-red-600 text-white"
                        : "bg-black/50 text-white opacity-0 group-hover:opacity-100"
                    }`}
                    title={
                      deleteConfirm === item.id
                        ? "Klik nogmaals om te verwijderen"
                        : "Verwijderen"
                    }
                  >
                    {deleteConfirm === item.id ? (
                      <X className="h-3.5 w-3.5" />
                    ) : (
                      <Trash2 className="h-3.5 w-3.5" />
                    )}
                  </button>
                )}

                {/* Selection indicator */}
                {isSelectMode && isSelected && (
                  <div className="absolute inset-0 flex items-center justify-center bg-primary/20">
                    <div className="rounded-full bg-primary p-1">
                      <svg
                        className="h-4 w-4 text-white"
                        fill="none"
                        stroke="currentColor"
                        viewBox="0 0 24 24"
                      >
                        <path
                          strokeLinecap="round"
                          strokeLinejoin="round"
                          strokeWidth={2}
                          d="M5 13l4 4L19 7"
                        />
                      </svg>
                    </div>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      {/* Pagination */}
      {totalPages > 1 && (
        <div className="flex items-center justify-between">
          <p className="text-sm text-muted-foreground">
            {total} bestand{total !== 1 ? "en" : ""} totaal
          </p>
          <div className="flex items-center gap-1">
            <button
              type="button"
              onClick={() => onPageChange(page - 1)}
              disabled={page <= 1}
              className="rounded-md p-1.5 text-muted-foreground hover:bg-muted hover:text-foreground disabled:opacity-50 disabled:hover:bg-transparent"
            >
              <ChevronLeft className="h-4 w-4" />
            </button>
            <span className="px-3 text-sm text-muted-foreground">
              Pagina {page} van {totalPages}
            </span>
            <button
              type="button"
              onClick={() => onPageChange(page + 1)}
              disabled={page >= totalPages}
              className="rounded-md p-1.5 text-muted-foreground hover:bg-muted hover:text-foreground disabled:opacity-50 disabled:hover:bg-transparent"
            >
              <ChevronRight className="h-4 w-4" />
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
