"use client";

import { useState } from "react";
import {
  Plus,
  Pencil,
  Trash2,
  X,
  Loader2,
  FolderOpen,
  FileText,
} from "lucide-react";
import type { Category } from "../../types";
import { slugify } from "../../utils";

interface CategoryWithCount extends Category {
  article_count?: number;
}

interface CategoryManagerProps {
  categories: CategoryWithCount[];
  onCreate: (data: { name: string; slug: string; description?: string }) => void;
  onUpdate: (
    id: string,
    data: { name: string; slug: string; description?: string },
  ) => void;
  onDelete: (id: string) => void;
}

export function CategoryManager({
  categories,
  onCreate,
  onUpdate,
  onDelete,
}: CategoryManagerProps) {
  const [newName, setNewName] = useState("");
  const [newDescription, setNewDescription] = useState("");
  const [isCreating, setIsCreating] = useState(false);

  const [editingId, setEditingId] = useState<string | null>(null);
  const [editName, setEditName] = useState("");
  const [editDescription, setEditDescription] = useState("");

  const [deleteConfirm, setDeleteConfirm] = useState<string | null>(null);

  function handleCreate() {
    if (!newName.trim()) return;
    setIsCreating(true);
    try {
      onCreate({
        name: newName.trim(),
        slug: slugify(newName.trim()),
        description: newDescription.trim() || undefined,
      });
      setNewName("");
      setNewDescription("");
    } finally {
      setIsCreating(false);
    }
  }

  function startEdit(category: CategoryWithCount) {
    setEditingId(category.id);
    setEditName(category.name);
    setEditDescription(category.description ?? "");
  }

  function handleUpdate() {
    if (!editingId || !editName.trim()) return;
    onUpdate(editingId, {
      name: editName.trim(),
      slug: slugify(editName.trim()),
      description: editDescription.trim() || undefined,
    });
    setEditingId(null);
    setEditName("");
    setEditDescription("");
  }

  function cancelEdit() {
    setEditingId(null);
    setEditName("");
    setEditDescription("");
  }

  function handleDelete(id: string) {
    if (deleteConfirm === id) {
      onDelete(id);
      setDeleteConfirm(null);
    } else {
      setDeleteConfirm(id);
    }
  }

  return (
    <div className="space-y-6">
      {/* Add new category form */}
      <div className="rounded-lg border border-border bg-white p-4">
        <h3 className="mb-3 flex items-center gap-2 text-sm font-medium text-foreground">
          <Plus className="h-4 w-4" />
          Nieuwe categorie
        </h3>
        <div className="space-y-3">
          <input
            type="text"
            value={newName}
            onChange={(e) => setNewName(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === "Enter") handleCreate();
            }}
            placeholder="Naam van de categorie..."
            className="w-full rounded-lg border border-border bg-secondary px-3 py-2 text-sm text-foreground placeholder:text-muted-foreground focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
          />
          <input
            type="text"
            value={newDescription}
            onChange={(e) => setNewDescription(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === "Enter") handleCreate();
            }}
            placeholder="Beschrijving (optioneel)..."
            className="w-full rounded-lg border border-border bg-secondary px-3 py-2 text-sm text-foreground placeholder:text-muted-foreground focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
          />
          {newName.trim() && (
            <p className="text-xs text-muted-foreground">
              Slug: {slugify(newName.trim())}
            </p>
          )}
          <button
            type="button"
            onClick={handleCreate}
            disabled={!newName.trim() || isCreating}
            className="inline-flex items-center gap-2 rounded-lg bg-primary px-4 py-2 text-sm font-medium text-white hover:bg-primary/90 disabled:opacity-50"
          >
            {isCreating ? (
              <Loader2 className="h-4 w-4 animate-spin" />
            ) : (
              <Plus className="h-4 w-4" />
            )}
            Toevoegen
          </button>
        </div>
      </div>

      {/* Category list */}
      <div className="overflow-hidden rounded-lg border border-border">
        {categories.length === 0 ? (
          <div className="flex flex-col items-center justify-center px-4 py-12 text-center">
            <FolderOpen className="mb-3 h-8 w-8 text-muted-foreground" />
            <p className="text-sm text-muted-foreground">
              Nog geen categorie&euml;n aangemaakt.
            </p>
          </div>
        ) : (
          <ul className="divide-y divide-border">
            {categories.map((category) => (
              <li
                key={category.id}
                className="bg-white transition-colors hover:bg-muted/50"
              >
                {editingId === category.id ? (
                  /* Inline edit mode */
                  <div className="space-y-2 p-4">
                    <input
                      type="text"
                      value={editName}
                      onChange={(e) => setEditName(e.target.value)}
                      onKeyDown={(e) => {
                        if (e.key === "Enter") handleUpdate();
                        if (e.key === "Escape") cancelEdit();
                      }}
                      className="w-full rounded-lg border border-border bg-secondary px-3 py-2 text-sm text-foreground focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
                      autoFocus
                    />
                    <input
                      type="text"
                      value={editDescription}
                      onChange={(e) => setEditDescription(e.target.value)}
                      onKeyDown={(e) => {
                        if (e.key === "Enter") handleUpdate();
                        if (e.key === "Escape") cancelEdit();
                      }}
                      placeholder="Beschrijving (optioneel)..."
                      className="w-full rounded-lg border border-border bg-secondary px-3 py-2 text-sm text-foreground placeholder:text-muted-foreground focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
                    />
                    {editName.trim() && (
                      <p className="text-xs text-muted-foreground">
                        Slug: {slugify(editName.trim())}
                      </p>
                    )}
                    <div className="flex gap-2">
                      <button
                        type="button"
                        onClick={handleUpdate}
                        disabled={!editName.trim()}
                        className="inline-flex items-center gap-1 rounded-md bg-primary px-3 py-1.5 text-xs font-medium text-white hover:bg-primary/90 disabled:opacity-50"
                      >
                        Opslaan
                      </button>
                      <button
                        type="button"
                        onClick={cancelEdit}
                        className="inline-flex items-center gap-1 rounded-md border border-border px-3 py-1.5 text-xs font-medium text-foreground hover:bg-muted"
                      >
                        <X className="h-3 w-3" />
                        Annuleren
                      </button>
                    </div>
                  </div>
                ) : (
                  /* Display mode */
                  <div className="flex items-center justify-between px-4 py-3">
                    <div className="min-w-0 flex-1">
                      <button
                        type="button"
                        onClick={() => startEdit(category)}
                        className="text-left"
                      >
                        <span className="font-medium text-foreground hover:text-primary">
                          {category.name}
                        </span>
                      </button>
                      {category.description && (
                        <p className="mt-0.5 text-xs text-muted-foreground">
                          {category.description}
                        </p>
                      )}
                      <p className="mt-0.5 text-xs text-muted-foreground">
                        /{category.slug}
                      </p>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className="inline-flex items-center gap-1 text-xs text-muted-foreground">
                        <FileText className="h-3 w-3" />
                        {category.article_count ?? 0}
                      </span>
                      <button
                        type="button"
                        onClick={() => startEdit(category)}
                        className="rounded-md p-1.5 text-muted-foreground hover:bg-muted hover:text-foreground"
                        title="Bewerken"
                      >
                        <Pencil className="h-4 w-4" />
                      </button>
                      <button
                        type="button"
                        onClick={() => handleDelete(category.id)}
                        className={`rounded-md p-1.5 transition-colors ${
                          deleteConfirm === category.id
                            ? "bg-red-100 text-red-600"
                            : "text-muted-foreground hover:bg-muted hover:text-foreground"
                        }`}
                        title={
                          deleteConfirm === category.id
                            ? "Klik nogmaals om te verwijderen"
                            : "Verwijderen"
                        }
                      >
                        <Trash2 className="h-4 w-4" />
                      </button>
                    </div>
                  </div>
                )}
              </li>
            ))}
          </ul>
        )}
      </div>
    </div>
  );
}
