"use client";

import { useState } from "react";
import { Plus, X, Search, Loader2, Tags } from "lucide-react";
import type { Tag } from "../../types";
import { slugify } from "../../utils";

interface TagManagerProps {
  tags: Tag[];
  onCreate: (data: { name: string; slug: string }) => void;
  onDelete: (id: string) => void;
}

export function TagManager({ tags, onCreate, onDelete }: TagManagerProps) {
  const [newTagName, setNewTagName] = useState("");
  const [searchQuery, setSearchQuery] = useState("");
  const [isCreating, setIsCreating] = useState(false);
  const [deleteConfirm, setDeleteConfirm] = useState<string | null>(null);

  const filteredTags = searchQuery
    ? tags.filter((t) =>
        t.name.toLowerCase().includes(searchQuery.toLowerCase()),
      )
    : tags;

  function handleCreate() {
    const name = newTagName.trim();
    if (!name) return;
    if (tags.some((t) => t.name.toLowerCase() === name.toLowerCase())) return;

    setIsCreating(true);
    try {
      onCreate({ name, slug: slugify(name) });
      setNewTagName("");
    } finally {
      setIsCreating(false);
    }
  }

  function handleDelete(id: string) {
    if (deleteConfirm === id) {
      onDelete(id);
      setDeleteConfirm(null);
    } else {
      setDeleteConfirm(id);
    }
  }

  return (
    <div className="space-y-4">
      {/* Add new tag */}
      <div className="flex gap-2">
        <div className="relative flex-1">
          <Plus className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
          <input
            type="text"
            value={newTagName}
            onChange={(e) => setNewTagName(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === "Enter") handleCreate();
            }}
            placeholder="Nieuwe tag toevoegen..."
            className="w-full rounded-lg border border-border bg-secondary px-10 py-2 text-sm text-foreground placeholder:text-muted-foreground focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
          />
        </div>
        <button
          type="button"
          onClick={handleCreate}
          disabled={!newTagName.trim() || isCreating}
          className="inline-flex items-center gap-2 rounded-lg bg-primary px-4 py-2 text-sm font-medium text-white hover:bg-primary/90 disabled:opacity-50"
        >
          {isCreating ? (
            <Loader2 className="h-4 w-4 animate-spin" />
          ) : (
            <Plus className="h-4 w-4" />
          )}
          Toevoegen
        </button>
      </div>

      {/* Search / filter */}
      <div className="relative">
        <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
        <input
          type="text"
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
          placeholder="Tags filteren..."
          className="w-full rounded-lg border border-border bg-secondary px-10 py-2 text-sm text-foreground placeholder:text-muted-foreground focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
        />
      </div>

      {/* Tag grid */}
      {filteredTags.length === 0 ? (
        <div className="flex flex-col items-center justify-center rounded-lg border border-border px-4 py-12 text-center">
          <Tags className="mb-3 h-8 w-8 text-muted-foreground" />
          <p className="text-sm text-muted-foreground">
            {searchQuery
              ? "Geen tags gevonden voor deze zoekopdracht."
              : "Nog geen tags aangemaakt."}
          </p>
        </div>
      ) : (
        <div className="flex flex-wrap gap-2">
          {filteredTags.map((tag) => (
            <span
              key={tag.id}
              className={`group inline-flex items-center gap-1.5 rounded-full px-3 py-1.5 text-sm font-medium transition-colors ${
                deleteConfirm === tag.id
                  ? "bg-red-100 text-red-700"
                  : "bg-accent text-accent-foreground"
              }`}
            >
              {tag.name}
              {tag.article_count !== undefined && (
                <span className="text-xs opacity-60">
                  ({tag.article_count})
                </span>
              )}
              <button
                type="button"
                onClick={() => handleDelete(tag.id)}
                className={`ml-0.5 rounded-full p-0.5 transition-colors ${
                  deleteConfirm === tag.id
                    ? "text-red-700 hover:bg-red-200"
                    : "text-muted-foreground opacity-0 hover:bg-muted hover:text-foreground group-hover:opacity-100"
                }`}
                title={
                  deleteConfirm === tag.id
                    ? "Klik nogmaals om te verwijderen"
                    : "Verwijderen"
                }
              >
                <X className="h-3.5 w-3.5" />
              </button>
            </span>
          ))}
        </div>
      )}

      {/* Count */}
      <p className="text-xs text-muted-foreground">
        {filteredTags.length} van {tags.length} tag{tags.length !== 1 ? "s" : ""}
      </p>
    </div>
  );
}
